SELECT COUNT(*) FROM POST


        AND title LIKE CONCAT('%', #{keyword}, '%')


        AND category = #{category}


        AND location = #{location}


        AND title LIKE CONCAT('%', #{keyword}, '%')

SELECT p.*, u.login_id as loginId FROM post p LEFT JOIN user u ON p.user_id = u.id AND p.category = #{category} AND p.location = #{location}
AND p.title LIKE CONCAT('%', #{keyword}, '%') AND p.content LIKE CONCAT('%', #{keyword}, '%') AND u.login_id LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.id DESC LIMIT #{pageable.pageSize} OFFSET #{pageable.offset}

SELECT COUNT(*) FROM post

    AND category = #{category}
    AND location = #{location}

SELECT type
FROM post_reaction
WHERE post_id = #{postId} AND user_id = #{userId}

SELECT * FROM post
WHERE user_id = #{userId}
ORDER BY id DESC
LIMIT #{pageable.pageSize} OFFSET #{pageable.offset}

SELECT r.id, r.post_id, r.user_id, r.content, r.created_at, r.updated_at, p.title as postTitle
FROM post_reply r
JOIN post p ON r.post_id = p.id
WHERE r.user_id = #{userId}
ORDER BY r.id DESC
LIMIT #{pageable.pageSize} OFFSET #{pageable.offset}

